function topKStudents(positive_feedback, negative_feedback, report, student_id, k) {
    let points = {};

    for (let i = 0; i < report.length; i++) {
        let pos_count = 0, neg_count = 0;
        for (const pos of positive_feedback) {
            let pos_index = report[i].indexOf(pos);
            while (pos_index !== -1) {
                pos_count++;
                pos_index = report[i].indexOf(pos, pos_index + pos.length);
            }
        }
        for (const neg of negative_feedback) {
            let neg_index = report[i].indexOf(neg);
            while (neg_index !== -1) {
                neg_count++;
                neg_index = report[i].indexOf(neg, neg_index + neg.length);
            }
        }
        points[student_id[i]] = (points[student_id[i]] || 0) + 3 * pos_count - neg_count;
    }

    let students = [...student_id];
    students.sort((a, b) => points[a] !== points[b] ? points[b] - points[a] : a - b);
    return students.slice(0, k);
}
