solutionCode.java:
    ```java
import java.util.*;

public List<Integer> topKStudents(String[] positiveFeedback, String[] negativeFeedback, String[] report,
                                   int[] studentId, int k) {
    Map<Integer, Integer> points = new HashMap<>();

    for (int i = 0; i < report.length; i++) {
        int posCount = 0, negCount = 0;

        for (String pos : positiveFeedback) {
            int posIndex = report[i].indexOf(pos);
            while (posIndex != -1) {
                posCount++;
                posIndex = report[i].indexOf(pos, posIndex + pos.length());
            }
        }

        for (String neg : negativeFeedback) {
            int negIndex = report[i].indexOf(neg);
            while (negIndex != -1) {
                negCount++;
                negIndex = report[i].indexOf(neg, negIndex + neg.length());
            }
        }

        int studentPoints = points.getOrDefault(studentId[i], 0) + 3 * posCount - negCount;
        points.put(studentId[i], studentPoints);
    }

    List<Integer> students = new ArrayList<>();
    for (int id : studentId) {
      students.add(id);
    }

    Collections.sort(students, (a, b) -> points.get(a) != points.get(b) ? points.get(b) - points.get(a) : a - b);

    return students.subList(0, k);
}
```


